from __future__ import annotations

import math
import re
import textwrap
import xml.etree.ElementTree as ET
from dataclasses import dataclass
from pathlib import Path
from zipfile import ZipFile


ROOT = Path(__file__).resolve().parent
SOURCE_DOCX = ROOT / "уп 02 2 часть  (2).docx"
OUTPUT_DOC = ROOT / "Титульник Часть 2.doc"

NS = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
WORDS_PER_PAGE = 190
MIN_BODY_WORDS = 15000


@dataclass
class Section:
    number: str
    title: str
    base_range: tuple[int, int] | None
    extras: list[str]
    page_break_before: bool = False


def extract_paragraphs(path: Path) -> list[str]:
    with ZipFile(path) as archive:
        root = ET.fromstring(archive.read("word/document.xml"))

    result: list[str] = []
    for paragraph in root.findall(".//w:body/w:p", NS):
        chunks = [node.text or "" for node in paragraph.findall(".//w:t", NS)]
        text = "".join(chunks).strip()
        if text:
            result.append(re.sub(r"\s+", " ", text))
    return result


def pick(paragraphs: list[str], start: int, end: int) -> list[str]:
    skipped_prefixes = ("Рисунок", "Таблица", "СОДЕРЖАНИЕ")
    result: list[str] = []
    for text in paragraphs[start - 1 : end]:
        if text.startswith(skipped_prefixes):
            continue
        result.append(text)
    return result


def clean(text: str) -> str:
    return re.sub(r"\s+", " ", textwrap.dedent(text).strip())


def escape_rtf(text: str) -> str:
    text = text.replace("\\", "\\\\").replace("{", "\\{").replace("}", "\\}")
    escaped: list[str] = []
    for char in text:
        code = ord(char)
        if char == "\n":
            escaped.append("\\line ")
        elif 32 <= code <= 126:
            escaped.append(char)
        else:
            if code > 32767:
                code -= 65536
            escaped.append(f"\\u{code}?")
    return "".join(escaped)


def para(text: str, *, bold: bool = False, center: bool = False, uppercase: bool = False) -> str:
    text = clean(text)
    if uppercase:
        text = text.upper()
    align = "\\qc" if center else "\\qj"
    weight_start = "\\b " if bold else ""
    weight_end = "\\b0 " if bold else ""
    return f"\\pard\\sa0\\sb120\\fi709\\li0\\ri0\\sl360\\slmult1{align}\\f0\\fs28 {weight_start}{escape_rtf(text)}{weight_end}\\par\n"


def title_para(text: str, *, bold: bool = False, center: bool = True, before: int = 0, after: int = 0) -> str:
    weight_start = "\\b " if bold else ""
    weight_end = "\\b0 " if bold else ""
    return (
        f"\\pard\\sa0\\sb{before}\\fi0\\qc\\f0\\fs28 {weight_start}{escape_rtf(clean(text))}"
        f"{weight_end}\\par\\sa{after}\n"
    )


def heading1(number: str, title: str) -> str:
    return (
        "\\page\n"
        f"\\pard\\sa0\\sb120\\qc\\f0\\fs28\\b {escape_rtf(f'{number} {title}')}"
        "\\b0\\par\n"
    )


def heading2(number: str, title: str) -> str:
    return (
        f"\\pard\\sa0\\sb180\\fi0\\ql\\f0\\fs28\\b {escape_rtf(f'{number} {title}')}"
        "\\b0\\par\n"
    )


def contents_line(title: str, page: int, indent_level: int = 0) -> str:
    indent = 0 if indent_level == 0 else 425 * indent_level
    dotted = "." * max(6, 110 - len(title))
    text = f"{title} {dotted} {page}"
    return f"\\pard\\sa0\\sb60\\fi0\\li{indent}\\qj\\f0\\fs28 {escape_rtf(text)}\\par\n"


def estimate_pages(block_words: int) -> int:
    return max(1, math.ceil(block_words / WORDS_PER_PAGE))


def word_count(texts: list[str]) -> int:
    return sum(len(re.findall(r"[A-Za-zА-Яа-яЁё0-9-]+", text)) for text in texts)


